fn sanitize_filename(filename: &str) -> Result<&str, ConversionError> {
    // Reject empty filenames
    if filename.is_empty() {
        return Err(ConversionError::InvalidFilename("Filename is empty".to_string()));
    }

    // Reject path traversal attempts
    if filename.contains("..") || filename.contains('/') || filename.contains('\\') {
        return Err(ConversionError::InvalidFilename(
            "Filename contains path traversal characters".to_string(),
        ));
    }

    // Reject null bytes
    if filename.contains('\0') {
        return Err(ConversionError::InvalidFilename(
            "Filename contains null bytes".to_string(),
        ));
    }

    // Only allow alphanumeric, dots, hyphens, underscores, and spaces
    if !filename.chars().all(|c| c.is_alphanumeric() || c == '.' || c == '-' || c == '_' || c == ' ') {
        return Err(ConversionError::InvalidFilename(
            "Filename contains disallowed characters".to_string(),
        ));
    }

    Ok(filename)
}

